for table in metadata['tables']:
    source_details = table['mapping_details'].split('->')[1].split('+')
    source_table = source_details[-1].strip().split()[0].lower()
    source_alias = table['target_alias']
    target_table = table['target_table']

    df = spark.read.format(metadata['runtime_config']['read_format']) \
        .option("header", "true") \
        .option("inferSchema", "true") \
        .load(metadata['runtime_config']['base_path'] + source_table + '.' + metadata['runtime_config']['read_format'])

    df = df.alias(source_alias)

    transformations = []
    for column in metadata['columns']:
        if column['target_table'] == source_alias:
            transformation = column['transformation'].split('=')[1].strip() + " as " + column['target_column']
